const ctx = $input.first().json;
if (!ctx.results?.resume_versions || ctx.results.resume_versions.length === 0) {
  throw new Error('No tailored resume versions available to apply with.');
}

// Fan out the tailored versions
return ctx.results.resume_versions.map(version => ({
  json: { version, ctx }
}));

const vData = $('Fan Out Versions').item.json;
const job = vData.version.job;

// Priority Recalculation (User Formula)
// ATS Score: 40%
// Opportunity Quality Score: 30% (Use job.quality_report.ghost_probability to infer quality if direct score absent)
// Hiring Probability: 15% (Mocked at 70 for now)
// Application Readiness: 10% (Map ATS Readiness to num)
// Deadline Urgency: 5% (Mocked at 50)

const atsScore = job.ats_evaluation?.overall_score || 0;
const qualityScore = 100 - (job.quality_report?.ghost_probability || 0) - (job.quality_report?.scam_risk || 0);
const hiringProb = 70; 
const readiness = job.ats_evaluation?.hiring_readiness === 'HIGH' ? 100 : (job.ats_evaluation?.hiring_readiness === 'MEDIUM' ? 60 : 30);
const urgency = 50;

const priorityScore = Math.round(
  (atsScore * 0.40) + 
  (qualityScore * 0.30) + 
  (hiringProb * 0.15) + 
  (readiness * 0.10) + 
  (urgency * 0.05)
);

let priorityLevel = 'LOW';
if (priorityScore >= 80) priorityLevel = 'HIGH';
else if (priorityScore >= 60) priorityLevel = 'MEDIUM';

const pkg = {
  priority_score: priorityScore,
  priority_level: priorityLevel,
  priority_explanation: `ATS (${atsScore}) 40%, Quality (${qualityScore}) 30%, Readiness (${readiness}) 10%, HiringProb 15%, Urgency 5%`,
  status: 'PREPARED',
  materials: {
    cover_letter: '',
    outreach: {}
  }
};

return [{
  json: { ...vData, pkg }
}];

const base = $('Calculate Priority').item.json;
const clRes = $('Gen Cover Letter').item.json;
const outRes = $('Gen Outreach').item.json;

base.pkg.materials.cover_letter = clRes.cover_letter;
base.pkg.materials.outreach = outRes.outreach;

return [{ json: base }];

const vData = $('Fan Out Versions').item.json;
return [{
  json: { 
    ...vData, 
    pkg: { status: 'DUPLICATE', priority_explanation: 'Skipped generation to prevent duplicate application in DB.' }
  }
}];

const allItems = $input.all();
const ctx = $('Fan Out Versions').first().json.ctx;

// Add application packages to context
ctx.results.applications = allItems.map(i => i.json);
ctx.agents_completed = [...(ctx.agents_completed || []), 'application_automation'];

return [{ json: ctx }];
